  const candidates = [
    grant.closeDate, grant.deadline, grant.dueDate, grant.due_date,
    grant.endDate, grant.end_date, grant.applicationDeadline, grant.application_deadline,
  ];
  for (const val of candidates) {
    if (!val || typeof val !== 'string') continue;
    const parsed = new Date(val);
    if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) return parsed;
  }
  if (grant.description) {
    const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
